(function() {
  var _isReturning = 1;
  var _cookieName = "rmk-visitor";
  var _cookieVal = getCookie(_cookieName);
  if (!_cookieVal || _cookieVal === '') {
    _isReturning = 0;
  }

  function getCookie(name) {
    var n = name + '=';
    var ca = document.cookie.split(';');
    for (var i = 0; i < ca.length; i++) {
      var c = ca[i];
      while (c.charAt(0) === ' ') c = c.substring(1);
      if (c.indexOf(n) === 0) return c.substring(n.length, c.length);
    }
    return '';
  }

  function getDevice() {
    var ua = navigator.userAgent;
    if (/Mobi|Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(ua)) return 'Mobile';
    if (/Tablet|iPad/i.test(ua)) return 'Tablet';
    return 'Desktop';
  }

  function uuid() {
    if (window.crypto && crypto.randomUUID) return crypto.randomUUID();
    var t = (new Date).getTime();
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      var r = (t + Math.random() * 16) % 16 | 0;
      t = Math.floor(t / 16);
      return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
    });
  }

  var COLLECT = "https://remarketingnew.vercel.app/api/collect";
  var CDN = "https://remarketingnew.vercel.app/api/cdn/";
  var SITE_ID = "site_a";

  var urlParams = new URLSearchParams(window.location.search);
  var source = urlParams.get('src') || 'organic';

  var visitorId = _cookieVal || uuid();

  // Set cookie for 1 day
  var expires = (new Date(Date.now() + 86400000)).toUTCString();
  document.cookie = _cookieName + '=' + visitorId + '; expires=' + expires + '; path=/';

  var payload = {
    v: visitorId,
    site_id: SITE_ID,
    source: source,
    event: 'viewPage',
    url: window.location.href,
    page: window.location.href,
    path: window.location.pathname,
    referrer: document.referrer,
    host: window.location.hostname,
    deviceType: getDevice(),
    isReturning: _isReturning,
    ts: Date.now()
  };

  // Step 1 — send to collect
  fetch(COLLECT, {
    method: 'POST',
    mode: 'no-cors',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  }).then(function() {
    loadCDN(visitorId);
  }).catch(function() {
    loadCDN(visitorId);
  });

  // Step 2 — load dynamic pixel script
  function loadCDN(uid) {
    var s = document.createElement('script');
    s.id = '__rmk_px';
    s.src = CDN + uid + '.js';
    s.async = true;
    document.head.appendChild(s);
  }

  // SPA support
  var lastPath = location.pathname;
  setInterval(function() {
    if (location.pathname !== lastPath) {
      lastPath = location.pathname;
      payload.event = 'page_view';
      payload.url = location.href;
      payload.path = location.pathname;
      fetch(COLLECT, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
    }
  }, 500);

  window.track = function(eventName, props) {
    fetch(COLLECT, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(Object.assign({}, payload, { event: eventName, props: props || {} }))
    });
  };
})();
